import {AppraisalRule} from './AppraisalRule';
import {SensorySystem} from '../../sensing/SensorySystem';
import {EmotionTrace} from '../../emotion/EmotionTrace';
import {EmotionSystem} from "../../EmotionSystem";
import {EmotionPoint, IdentityEvents, RuleImpactValues} from "../../common/Types";
import {IdentitySensor} from "../../sensing/sensors/IdentitySensor";

import parentLog from '../../log';
const log = parentLog.createChild('Appraisal.IdentityRule');

export {}

/**
 * @internal
 */
export class IdentityRule extends AppraisalRule {

    private identitySensor: IdentitySensor;

    constructor(name: string, parent: EmotionSystem) {
        super(name, parent);
    }

    /** @override */
    init(sensorySystem: SensorySystem) {
        this.identitySensor = <any> sensorySystem.getSensor(IdentitySensor.SENSOR_NAME);
        if (!this.identitySensor) {
            throw new Error(`Identity sensor is required, doesn't exist.`);
        }
        this.identitySensor.events.newDataEvent.on((sensorDataWrapper) => {
            log.info('Appraising data from identity data:', sensorDataWrapper.sensorData);

            let myTrace = new EmotionTrace([sensorDataWrapper], this, this.appraiseData(sensorDataWrapper.sensorData));
            this.events.impactTriggered.emit(myTrace);
        });
    }

    /** @override */
    appraiseData(input: IdentityEvents): EmotionPoint {
        switch(input) {
            case IdentityEvents.PRESENCE_STARTED:
                // Someone new is around, happiness boost mostly.
                return new EmotionPoint(RuleImpactValues.PRESENCE_STARTED_VALENCE, RuleImpactValues.PRESENCE_STARTED_CONFIDENCE);
            case IdentityEvents.ID_ACQUIRED:
                // ID'd someone, confidence boost mostly.
                return new EmotionPoint(RuleImpactValues.ID_ACQUIRED_VALENCE, RuleImpactValues.ID_ACQUIRED_CONFIDENCE);
            default:
                log.warn('got ID event with no matching emotion impact', input);
                return new EmotionPoint();
        }
    }

    dispose() {
        this.identitySensor.events.removeAllListeners();
    }

}
